INSERT INTO public.photos VALUES (24293, 'Anfiteatro siglo I', 'Mapa de situaciâ”œâ”‚n del anfiteatro romano de Zaragoza, construido en el siglo I de nuestra era, segâ”œâ•‘n propuesta de ubicaciâ”œâ”‚n de Pilar Diarte Blasco et al. ("Una nueva hipâ”œâ”‚tesis sobre la localizaciâ”œâ”‚n del anfiteatro de Caesaraugusta", Pyrenae, Revista de Prehistoria y Antigâ”œâ•‌edad del Mediterrâ”œأ­neo Occidental, nâ”œâ•‘m 44, 2013). Una hipâ”œâ”‚tesis anterior apunta a otro posible lugar: www.flickr.com/photos/126653716@N03/15725380705. La ubicaciâ”œâ”‚n en la huerta de Santa Engracia es desmentida en el estudio "Nuevas cuestiones sobre el anfiteatro de Zaragoza" (2016), de Josâ”œآ® David Mendoza: www.um.es/cepoat/pantarei/wp-content/uploads/2016/10/pant.... Fuentes de los datos: www.academia.edu/3687122/Una_nueva_hip%C3%B3tesis_sobre_l... prensa.unizar.es/noticias/1306/130613_z0_anfiteatro.pdf Fuente del plano:', 50, NULL, 99, 'Siglo XIX', 'CENTRO', 41.64905700, -0.87911200, '0101000020E610000047AD307DAF21ECBFB41EBE4C14D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15906334241.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15906334241.webp', 'https://www.flickr.com/photos/zaragozaantigua/15906334241/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24296, 'Santa Catalina c.1930', 'Foto Albareda, puerta de acceso a la Sala Capitular del monasterio de Santa Catalina. Ca. 1930. En la tercera dâ”œآ®cada del s. XIII fue fundado el monasterio de monjas de la Orden de San Damiâ”œأ­n, bajo la advocaciâ”œâ”‚n de Santa Catalina, por la existencia previa, en el lugar de su construcciâ”œâ”‚n, de una ermita dedicada a esta santa, cerca del Monasterio de Santa Engracia. La original fâ”œأ­brica del monasterio de Santa Catalina se realizâ”œâ”‚ en la primera mitad del s. XIV en formas mudâ”œآ®jares (con las habituales reformas barrocas en el XVII), de las que sâ”œâ”‚lo restan algunas partes de la actual iglesia, tras la desapariciâ”œâ”‚n de todas las antiguas dependencias, primero por los efectos de los duros combates de 1808-1809, y despuâ”œآ®s, en la tercera dâ”œآ®cada del s. XX, con las obras de reforma y ampliaciâ”œâ”‚n. Bajo esta â”œâ•‘ltima intervenciâ”œâ”‚n fue piqueteada la superviviente Sala Capitular, cuya puerta de acceso representa la imagen superior, antes del acto. Sic transit gloriae mundi. Fuente visual: "Zaragoza: visiones de una ciudad", Ayto. Zaragoza, 2004.', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.65028900, -0.87892500, '0101000020E6100000AA6054522720ECBF6AF981AB3CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/16360910582.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/16360910582.webp', 'https://www.flickr.com/photos/zaragozaantigua/16360910582/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24298, 'Pabellâ”œâ”‚n de Fomento 1908', 'Foto: Ignacio Coyne, 1908. Pabellâ”œâ”‚n del Ministerio de Fomento en la Exposiciâ”œâ”‚n Hispano Francesa de Zaragoza. Detrâ”œأ­s del fotâ”œâ”‚grafo, la Escuela de Artes. Fuente: dara.aragon.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64911200, -0.87886400, '0101000020E61000003F373465A71FECBF78B81D1A16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18989527873.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18989527873.webp', 'https://www.flickr.com/photos/zaragozaantigua/18989527873/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24305, 'Pabellâ”œâ”‚n de Fomento 1908', 'Imagen de la monumental puerta de acceso al Pabellâ”œâ”‚n del Ministerio de Fomento de la Exposiciâ”œâ”‚n Hispano Francesa de Zaragoza, obra del arquitecto Carlos Gato y Soldevilla. En planta rectangular de una altura, se alargaba hasta los 72 metros, y estaba ricamente decorado, imitando acabados propios de la piedra caliza, en un estilo muy al gusto del Modernismo "Sezession". En su interior, tres secciones mostraban los â”œâ•‘ltimos adelantos en lo referido a Agricultura, a Caminos, Minas y Montes, y al Canal de Aragâ”œâ”‚n y Cataluâ”œâ–’a. La presencia en la imagen de varias personas permite captar en su verdadera dimensiâ”œâ”‚n las proporciones y medidas de este Pabellâ”œâ”‚n, pues sin ellas, parecerâ”œآ،an colosales. Fuente visual: Revista Arquitectura y Construcciâ”œâ”‚n, 1908.', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64911200, -0.87886400, '0101000020E61000003F373465A71FECBF78B81D1A16D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19583826063.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19583826063.webp', 'https://www.flickr.com/photos/zaragozaantigua/19583826063/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24308, 'Huerta de Santa Engracia 1863', 'Plano de la Huerta de Santa Engracia de Zaragoza y alrededores en 1863. Fuente: â”¬أ­Aquâ”œآ،... Zaragoza!, Josâ”œآ® Blasco Ijazo, 1953.', 1863, 1863, 1863, 'Siglo XIX', 'CENTRO', 41.64886500, -0.87931300, '0101000020E610000022533E045523ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19692704800.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19692704800.webp', 'https://www.flickr.com/photos/zaragozaantigua/19692704800/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24310, 'Espacio Goya 2006', 'Recreaciâ”œâ”‚n virtual del proyecto de Herzog y De Meuron para crear un Espacio Goya en los edificios de la Escuela de Artes y el Museo de Zaragoza, en 2006. La prouesta, que debâ”œآ،a estar lista para los fastos de 2008, no prosperâ”œâ”‚. No obstante, se construyâ”œâ”‚ una nueva Escuela de Artes en la Margen Izquierda y se abandonâ”œâ”‚ la que nos ocupa. En 2015, Ibercaja, banco propietario del Museo Camâ”œâ”‚n Aznar, lo redenominâ”œâ”‚ "Museo Goya colecciâ”œâ”‚n Ibercaja", con la esperanza de ampliar su espacio aâ”œâ–’adiâ”œآ®ndole un solar municipal de la calle Santiago. Fuente visual: archidose.blogspot.com.es/2009/04/espacio-goya.html', 2006, 2006, 2006, 'Siglo XXI', 'CENTRO', 41.64873600, -0.87869200, '0101000020E6100000F83768AF3E1EECBF72DEFFC709D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/19924207315.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/19924207315.webp', 'https://www.flickr.com/photos/zaragozaantigua/19924207315/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24313, 'Vista aâ”œآ®rea plaza de los Sitios 1986', 'Foto: Josâ”œآ® Luis Pomarâ”œâ”‚n Vista aâ”œآ®rea del entorno de la plaza de los Sitios de Zaragoza. Al fondo, junto a los bloques de la calle Coâ”œآ،mbra, el gasâ”œâ”‚metro desmantelado. Fuente: Colecciâ”œâ”‚n Rafael Margalâ”œآ®.', 1986, 1986, 1986, 'Anos 80', 'CENTRO', 41.64897500, -0.87940100, '0101000020E6100000F33AE2900D24ECBFF775E09C11D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/22130364629.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/22130364629.webp', 'https://www.flickr.com/photos/zaragozaantigua/22130364629/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24317, 'Calle de Sancho y Gil 1928', 'Imagen de la nueva sede de la Mutua de Accidentes de Zaragoza, ubicada en la calle Sancho y Gil nâ”œâ•‘mero 4, en una parte del antiguo Jardâ”œآ،n Botâ”œأ­nico de Zaragoza, reurbanizado tras la Exposiciâ”œâ”‚n Hispano Francesa de 1908. El edificio fue diseâ”œâ–’ado por Marcelino Securun Orga, como una recreaciâ”œâ”‚n de las formas de los antiguos edificios seâ”œâ–’oriales de la ciudad de los siglos XV-XVI, en ladrillo. A su izquierda, la antigua Capilla de Jesâ”œâ•‘s Reparador, de las Religiosas Reparadoras del Sagrado Corazâ”œâ”‚n, que serâ”œآ،a reconstruida de nueva planta en los aâ”œâ–’os 60. Fuente visual: www.maz.es/', 1928, 1928, 1928, 'Anos 20', 'CENTRO', 41.64990100, -0.87830400, '0101000020E610000080457EFD101BECBFA051BAF42FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30647425396.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30647425396.webp', 'https://www.flickr.com/photos/zaragozaantigua/30647425396/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24320, 'Huerta de Santa Engracia 1908', 'Imagen del efâ”œآ،mero pabellâ”œâ”‚n del Ministerio de Fomento levantado en la Exposiciâ”œâ”‚n Hispano Francesa de 1908, en la antigua huerta de Santa Engracia. A la izquierda, un molino de viento extractor de agua con publicidad de la local "Fundiciâ”œâ”‚n Pellicer y Juan", y detrâ”œأ­s, muro perimetral de la huerta del convento de Santa Catalina. Detrâ”œأ­s del pabellâ”œâ”‚n, altos â”œأ­rboles del Jardâ”œآ،n Botâ”œأ­nico. Al fondo, a la derecha, sobresale el perdurable "Edificio de Artes e Industrias", luego "Escuelas de Industrias y Bellas Artes, de Comercio y de Artes y Oficios", con sus caracterâ”œآ،sticas y efâ”œآ،meras reproducciones de la Tour Eiffel. El Monumento a los Sitios estaba justo donde termina la imagen, a la derecha, casi frente a la puerta principal de ingreso al pabellâ”œâ”‚n de Fomento. Esta imagen, capturada por Ignacio Coynâ”œآ® ("Coyne Foto"), formaba parte de una serie de postales dedicada a la Expo 1908. Fuente visual: www.ebay.es/', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64914000, -0.87914100, '0101000020E6100000DA53724EEC21ECBF4243FF0417D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31362743796.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31362743796.webp', 'https://www.flickr.com/photos/zaragozaantigua/31362743796/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24322, 'Calle Moret 2008', 'Foto: Josâ”œآ® Miguel Marco. Vista desde la plaza de Los Sitios de la calle de Segismundo Moret. Este vial fue propuesto para albergar en su subsuelo un aparcamiento, en 1989, 1994 y 2008. En marzo de 2016 comenzaron, esta vez sâ”œآ،, las obras, para su inauguraciâ”œâ”‚n en 2017. Fuente: Heraldo de Aragâ”œâ”‚n.', 2008, 2008, 2008, 'Siglo XXI', 'CENTRO', 41.64865700, -0.87858400, '0101000020E6100000603E59315C1DECBF26A94C3107D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/31863403134.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/31863403134.webp', 'https://www.flickr.com/photos/zaragozaantigua/31863403134/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24330, 'Arquitecto Magdalena 1929', 'Imagen capturada durante las obras de ampliaciâ”œâ”‚n y reforma del franciscano convento de Santa Catalina. En este caso, se trata del nuevo pabellâ”œâ”‚n de tres plantas de altura proyectado por Luis de La Figuera en estilo historicista y neogâ”œâ”‚tico, con fachada a la nueva calle del Arquitecto Magdalena. Al fondo, a la derecha, el muro de la despejada zona conventual que hacâ”œآ،a esquina a la plaza de Castelar. Hacia la izquierda, la calle de San Miguel. Este fue el convento mâ”œأ­s antiguo de la ciudad, fundado en el primer tercio del siglo XIII, si bien la construcciâ”œâ”‚n del mismo data del siglo siguiente, en gâ”œâ”‚tico mudâ”œآ®jar, con reformas posteriores. Su extensiâ”œâ”‚n, entonces, era mucho mâ”œأ­s destacada, incluyendo gran claustro y amplia zona de huerta delimitada por la muralla de rejola. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65003800, -0.87911900, '0101000020E6100000E659492BBE21ECBF2194F77134D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36565173482.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36565173482.webp', 'https://www.flickr.com/photos/zaragozaantigua/36565173482/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24331, 'Arquitecto Magdalena 1929', 'Imagen capturada durante las obras de ampliaciâ”œâ”‚n y reforma del franciscano convento de Santa Catalina (a la derecha) como consecuencia de la reurbanizaciâ”œâ”‚n de la zona, que incluyâ”œâ”‚ la apertura de un nuevo vial que prolongaba la calle de Santa Catalina, y que recibirâ”œآ،a el nombre de Arquitecto Magdalena. A la izquierda, irregular traza con algunos restos edilicios previos a la apertura del nuevo vial, luego derribados y sobre cuyos solares se levantarâ”œأ­n el nâ”¬â•‘ 22 de la calle de San Miguel. el nâ”¬â•‘ 4 de Arquitecto Magdalena y el nâ”¬â•‘ 14 de la plaza de Castelar. Al fondo, la estrecha calle de Santa Catalina, a cuya izquierda queda el antiguo nâ”¬â•‘ 16 de esa calle, que serâ”œآ،a derribado dâ”œآ®cadas despuâ”œآ®s para acometer una nueva ampliaciâ”œâ”‚n del colegio de las Hijas de la Caridad de Santa Ana. A la derecha, el nâ”¬â•‘ 17 de la calle de San Miguel. El proyecto de apertura de este nuevo vial incluâ”œآ،a â”œأ­rboles a ambos lados de la calle, para dar mâ”œأ­s lustre (y sombra) a una codiciada zona que era considerada &quot;aristocrâ”œأ­tica&quot;. Fuente visual: www.mecd.gob.es/.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.65003800, -0.87911900, '0101000020E6100000E659492BBE21ECBF2194F77134D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36597010771.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36597010771.webp', 'https://www.flickr.com/photos/zaragozaantigua/36597010771/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24337, 'Plaza de Castelar 1929', 'Imagen capturada desde la plaza de Emilio Castelar y centrada en el reciente inmueble del nâ”¬â•‘ 12 de la calle del Arquitecto Magdalena (actual nâ”¬â•‘ 18 de la plaza de los Sitios), en el centro de la despejada manzana delimitada entre las calles de Felipe Sanclemente, hacia la izquierda, y la de Jerâ”œâ”‚nimo Zurita, hacia la derecha. Este edificio, proyectado por Fernando Garcâ”œآ،a Mercadal, es considerado el primero del racionalismo arquitectâ”œâ”‚nico construido en la ciudad. En 1956 se le aâ”œâ–’adirâ”œأ­ una planta extra, que le darâ”œآ،a su altura actual.', 1929, 1929, 1929, 'Anos 20', 'CENTRO', 41.64946600, -0.87970000, '0101000020E61000008351499D8026ECBF95EEAEB321D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/49948509017.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/49948509017.webp', 'https://www.flickr.com/photos/zaragozaantigua/49948509017/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24339, 'Plaza de los Sitios 1990', 'El CAI Zaragoza, equipo de baloncesto de la ciudad, asâ”œآ، denominado entre 1982 y 1992, ganâ”œâ”‚ la Copa del Rey en dos ocasiones. En 1984 contra el FC Barcelona, y en 1990 contra el Joventut de Badalona. En la foto, posado del conjunto en el monumento a los Sitios de la plaza homâ”œâ”‚nima, celebrando la â”œâ•‘ltima victoria mencionada. De pie y de izquierda a derecha: Fernando Arcega, Joaquâ”œآ،n Ruiz Lorente, Francisco Murcia, Josâ”œآ® Luis Oliete y Jesâ”œâ•‘s "Chuchi" Carrera (tâ”œآ®cnicos), Mark Davis, Josâ”œآ® Miguel Hernâ”œأ­ndez, Aleksander Belostenny. Sentados y de izquierda a derecha: Luis Melendo (delegado del equipo), Francisco "Paco" Binaburo (fisioterapeuta), Josâ”œآ® â”œأ¼ngel "Pepe" Arcega, Santiago Aldama, Francisco "Paco" Zapata, Quique Andreu, Alberto Angulo, Daniel â”œأ¼lvarez, Josâ”œآ® "Pepe" Costa (preparador fâ”œآ،sico) y Fâ”œآ®lix Gâ”œâ”‚mez (doctor).', 1990, 1990, 1990, 'Anos 90', 'CENTRO', 41.64890400, -0.87938900, '0101000020E6100000E2C96E66F423ECBF2E1F49490FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50213919188.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50213919188.webp', 'https://www.flickr.com/photos/zaragozaantigua/50213919188/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24340, 'Plaza de los Sitios 1998', 'Imagen capturada durante las obras de urbanizaciâ”œâ”‚n y embellecimiento de la plaza de los Sitios que al homâ”œâ”‚nimo monumento le dotaron de la fuente que desde entonces lo rodea, y que fueron acometidas durante la etapa de Luisa Fernanda Rudi como alcaldesa. Al fondo y sobre los â”œأ­rboles de la plaza emergen los edificios del Museo Provincial y Escuela de Bellas Artes.', 1998, 1998, 1998, 'Anos 90', 'CENTRO', 41.64890400, -0.87938900, '0101000020E6100000E2C96E66F423ECBF2E1F49490FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/50512143803.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/50512143803.webp', 'https://www.flickr.com/photos/zaragozaantigua/50512143803/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24342, 'Plaza de Josâ”œآ® Antonio 1978', '"Plaza de Josâ”œآ® Antonio". â”œأ´leo sobre lienzo, 73 x 54 cm, Carmen Faci, 1978. Preside el cuadro el Monumento a los Sitios.', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64896400, -0.87944800, '0101000020E6100000200BD1217024ECBF03249A4011D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/53637579633.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/53637579633.webp', 'https://www.flickr.com/photos/zaragozaantigua/53637579633/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24497, 'Calle de San Miguel c.1973', 'El antiguo nâ”¬â•‘ 45 de la calle de San Miguel, esquinero con la de Comandante Repollâ”œآ®s, y vecino del pâ”œآ®treo y caracterâ”œآ،stico nâ”¬â•‘ 43, fue derribado a mediados de los aâ”œâ–’os 60, y sobre su solar se construyâ”œâ”‚ un nuevo bloque de viviendas con notable desarrollo vertical. En su planta calle abriâ”œâ”‚ al pâ”œâ•‘blico un establecimiento comercial denominado "Supermercado del Hogar", que ahora cumple su aniversario 50. En la imagen, achaflanado y nutrido escaparate de esta tienda a lo "13 Rue del Percebe", una de sus originales seâ”œâ–’as de identidad, como gran expositor del aparataje domâ”œآ®stico asociado a una vida moderna y elâ”œآ®ctrica a 220v. En el cartel anunciador, que perdura, referencia a las clâ”œأ­sicas marcas comerciales "De Wald" (auto-radio y TV), e "Invicta" (radio y TV). Fuente visual: amable aportaciâ”œâ”‚n personal de Jesus Pablo Corvinos.', 1973, 1973, 1973, 'Anos 70', 'CENTRO', 41.64981000, -0.87698600, '0101000020E61000006C98A1F14410ECBF904E5DF92CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/30209167972.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/30209167972.webp', 'https://www.flickr.com/photos/zaragozaantigua/30209167972/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24897, 'Calle de San Miguel 1958', 'Dâ”œآ،a lluvioso en la calle de San Miguel, desde cierta altura en los aledaâ”œâ–’os de la plaza homâ”œâ”‚nima, con detalle de los reflejos de la luz sobre el mojado adoquinado y las zonas parcheadas con asfalto. A la derecha, la casa con revestimiento en piedra y puerta con forma de arco del nâ”¬â•‘ 43, cuyo singular aspecto fue acicate para el popular ejercicio de invenciâ”œâ”‚n de leyendas urbanas como la del duende o personaje aquâ”œآ، encerrado que nunca se cortâ”œâ”‚ las uâ”œâ–’as. Varias personas transitan el vial, junto a la esquina de la calle de Miguel Alluâ”œآ® Salvador, donde estaba la academia de conductores Aragâ”œâ”‚n. Fuente visual: Foto Josâ”œآ® Antonio Duce', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64980500, -0.87707500, '0101000020E610000054742497FF10ECBF7EE36BCF2CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15223546026.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15223546026.webp', 'https://www.flickr.com/photos/zaragozaantigua/15223546026/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (24976, 'Leoncio, del Botâ”œأ­nico 1913', 'Una de las iniciativas de la ilustrada "Real Sociedad Econâ”œâ”‚mica de Amigos del Paâ”œآ،s" de Zaragoza, fue establecer un "Jardâ”œآ،n experimental" como plantero de especies vegetales exâ”œâ”‚ticas y nativas, y como aulario para enseâ”œâ–’anza de la ciencia botâ”œأ­nica y su relaciâ”œâ”‚n con la medicina. Asâ”œآ،, arrendâ”œâ”‚ unos terrenos cerca de la plaza de San Miguel, medianera con las monjas de Santa Catalina, enfrente a las calles de Urreas y Rufas, y allâ”œآ، se construyeron aulas para alumnos, y el suelo fue dispuesto para cultivos, con su riego. Fue inaugurado en 1778. Los sucesos bâ”œآ®licos de 1808-09 lo dejaron arruinado, y los intentos por recuperarlo sâ”œâ”‚lo cuajaron en 1843, cuando se traspasâ”œâ”‚ su gestiâ”œâ”‚n a la Universidad, ya como "Jardâ”œآ،n Botâ”œأ­nico", en la misma ubicaciâ”œâ”‚n. En 1860 se extendâ”œآ،a por 3800 m2, con unas 1500 especies de plantas en nâ”œâ”‚mina, riego suficiente, y buena visual de las afueras de la ciudad. Se entraba por la calle de San Miguel nâ”¬â•‘ 30, y era visitable. Leoncio Gâ”œâ”‚mez Gimeno, perito agrâ”œâ”‚nomo, fue el primer jardinero de esta segunda y larga â”œآ®poca del botâ”œأ­nico, en el que estuvo trabajando hasta su retiro, muchas dâ”œآ®cadas despuâ”œآ®s. Esta imagen de Leoncio sentado, tomada junto a los invernaderos, formaba parte de un reportaje dedicado a su larga trayectoria como "Patriarca del Botâ”œأ­nico", y fue publicado en el local periâ”œâ”‚dico "La Crâ”œâ”‚nica" el 18 de abril de 1913. La progresiva urbanizaciâ”œâ”‚n del entorno de la antigua Huerta de Santa Engracia, tras la Expo de 1908, provocâ”œâ”‚ el "traslado" del Botâ”œأ­nico, en 1923, a unos amplios espacios en el paseo de Ruiseâ”œâ–’ores, donde se estaba levantando la Residencia de Estudiantes de la Universidad, que fue su vecina hasta 1936. En este traslado se consolida el cambio de orientaciâ”œâ”‚n del Botâ”œأ­nico, ya como un visual elemento de ornamentaciâ”œâ”‚n vegetal. En los aâ”œâ–’os 60 se levantarâ”œأ­ el nuevo Instituto Femenino Miguel Servet, inaugurado en 1965, con lo que nuevamente el Botâ”œأ­nico tendrâ”œأ­ que hacer las maletas, y en 1970 recabar en el parque Primo de Rivera, en donde perma', 1913, 1913, 1913, 'Anos 10', 'CENTRO', 41.64993900, -0.87839100, '0101000020E61000003B394371C71BECBF8EB27E3331D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20553570572.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20553570572.webp', 'https://www.flickr.com/photos/zaragozaantigua/20553570572/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25068, 'Cristo 1978', 'Por partes: 1. A la derecha, Cristo resucitado. Se trata de una de las denominaciones dadas a un predicador judâ”œآ،o que, segâ”œâ•‘n la tradiciâ”œâ”‚n, viviâ”œâ”‚ a comienzos del siglo I d.C. y fue crucificado en Jerusalâ”œآ®n, resucitando al tercer dâ”œآ،a, debido a su carâ”œأ­cter de segunda persona de la Santâ”œآ،sima Trinidad, o sea Dios. 2. A la izquierda, el autor de la figura, Jorge Albareda Agâ”œâ•‌eras, escultor catâ”œâ”‚lico siguiendo la tradiciâ”œâ”‚n de su familia, que parte de Manuel Albareda Cantavilla en el siglo XIX. Su hijo Jorge Albareda Cubeles traslada el negocio de Caspe a Zaragoza. Sus hijos Josâ”œآ® y Joaquâ”œآ،n Albareda Piazuelo, los primeros Hermanos Albareda, se instalan en la calle Alluâ”œآ® Salvador en 1939. La empresa se denomina "El Arte Crtistiano". Miguel â”œأ¼ngel y Jorge Albareda Agâ”œâ•‌eras, hijos de Joaquâ”œآ،n, fueron los siguientes Hermanos Albareda. Teodoro Albareda Albareda, hijo de Miguel â”œأ¼ngel Albareda, cerrâ”œâ”‚ el taller en 1996. 3. El edificio del taller, que aâ”œâ•‘n subsiste demediado, es el que alberga el encuentro de la foto del creador con el Creador. Actualmente y desde 2007, es propiedad municipal. Mâ”œأ­s informaciâ”œâ”‚n: tausiet.blogspot.com.es/2016/01/el-taller-de-los-hermanos... Fuente visual: Blog "Pasiâ”œâ”‚n por Zaragoza".', 1978, 1978, 1978, 'Anos 70', 'CENTRO', 41.64891200, -0.87713900, '0101000020E6100000037AE1CE8511ECBFB1FD648C0FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15109558296.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15109558296.webp', 'https://www.flickr.com/photos/zaragozaantigua/15109558296/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25157, 'Puerta del Duque 1861', 'Alzado parcial de la Puerta del Duque de la Victoria, obra de Josâ”œآ® de Yarza Miâ”œâ–’ana, levantada en 1861 junto a la iglesia de San Miguel de los Navarros, en honor del general Baldomero Espartero. Sustituyâ”œâ”‚ a la erigida en 1856, que se habâ”œآ،a venido abajo. Permaneciâ”œâ”‚ hasta 1919. Fuente: AMZ.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64954300, -0.87616100, '0101000020E610000022FB20CB8209ECBF412C9B3924D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/32044878371.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/32044878371.webp', 'https://www.flickr.com/photos/zaragozaantigua/32044878371/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
