INSERT INTO public.photos VALUES (25174, 'Entrada Expo 1908', 'Billete de entrada diurno a la Exposiciâ”œâ”‚n Internacional Hispano Francesa de 1908. El Pabellâ”œâ”‚n Central o de la Alimentaciâ”œâ”‚n estâ”œأ­ representado flanqueado por el escudo de Zaragoza y por Marianne, sâ”œآ،mbolo de la Repâ”œâ•‘blica de Francia. Fuente: www.todocoleccion.net', 1908, 1908, 1908, 'Anos 1900', 'CENTRO', 41.64891000, -0.87930300, '0101000020E61000003ECA880B4023ECBF10069E7B0FD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/36493592636.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/36493592636.webp', 'https://www.flickr.com/photos/zaragozaantigua/36493592636/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
