INSERT INTO public.photos VALUES (25439, 'Puente de San Josâ”œآ® c.1930', 'Imagen del puente de San Josâ”œآ® sobre el râ”œآ،o Huerva, como arranque de la calle de Miguel Servet. A la derecha, acceso desde el paseo de la Mina, la plaza de San Miguel, y la calle del Asalto. En el siglo XVI, la nueva y pâ”œآ®trea fâ”œأ­brica de este puente estaba ubicada unos 300 metros aguas abajo, en el principio del original camino de Bajo Aragâ”œâ”‚n, y a su vera, extramuros, fue levantado el convento de los carmelitas descalzos de San Josâ”œآ®, por lo que el "puente sobre el Huerva", el mâ”œأ­s importante sobre este râ”œآ،o en la ciudad, comenzâ”œâ”‚ a ser denominado "de San Josâ”œآ®". El de la imagen, era el puente construido en 1855, tras varios previos en madera (y en otras ubicaciones cercanas), alguno de los cuales se los llevâ”œâ”‚ por delante el Huerva en sus tremendas salidas de madre. En 1923 este puente fue ensanchado con proyecto del arquitecto Miguel â”œأ¼ngel Navarro Pâ”œآ®rez, reaprovechando la parte metâ”œأ­lica del puente de Santa Engracia al quedar â”œآ®ste soterrado por el cubrimiento de ese tramo del râ”œآ،o Huerva. A finales del siglo y principios del XXI fue objeto de mâ”œأ­s ensanches. Fuente visual: Estudio Coyne, AHPZ-DARA', 1930, 1930, 1930, 'Anos 30', 'CENTRO', 41.64880800, -0.87574200, '0101000020E6100000EA7937161406ECBF0CB1FA230CD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/26424022600.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/26424022600.webp', 'https://www.flickr.com/photos/zaragozaantigua/26424022600/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25452, 'San Miguel c.1910', 'Imagen capturada desde el puente de San Josâ”œآ®, centrada en el entorno de la iglesia parroquial de San Miguel de los Navarros y la aislada puerta del Duque de la Victoria, aâ”œâ•‘n con las casetas del cobro de consumos. Al fondo, la plaza de San Miguel. Sobre el firme del puente, tendido tranviario de la lâ”œآ،nea del Bajo Aragâ”œâ”‚n, tambiâ”œآ®n de acceso al cocherâ”œâ”‚n de los tranvâ”œآ،as. Fuente visual: "Puerta del Duque â”œآ® Iglesia de San Miguel", postal nâ”¬â•‘ 359 de la fototipia Castaâ”œâ–’eira y â”œأ¼lvarez (Madrid) en la serie "Zaragoza", en www.ebay.es/', 1910, 1910, 1910, 'Anos 10', 'CENTRO', 41.64951900, -0.87615100, '0101000020E61000003F726BD26D09ECBFB890477023D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/34741543325.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/34741543325.webp', 'https://www.flickr.com/photos/zaragozaantigua/34741543325/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25579, '&quot;El Tenis&quot; 1958', 'Foto Alpi. 08/12/1958. Imagen del partido de la Liga Espaâ”œâ–’ola de Baloncesto jugado entre el local C. D. Iberia y el inmaculado Real Madrid, en la cancha del R.Z.C. de Tenis. El equipo de la Villa y Corte sumâ”œâ”‚ 4 puntos mâ”œأ­s (49-53), y se llevâ”œâ”‚ la victoria. No hacâ”œآ،a demasiado fresco, el campo estaba abarrotado, y el â”œأ­rbitro no fue arbitrario. Todos contentos. Al fondo de la imagen, tras el muro, Miguel Servet. A la izquierda, edificios de vivienda de la calle Asalto, que en realidad son las traseras de los de la calle Reconquista, y que han supervivido hasta el momento. Enfrente, la enorme estructura del Garaje Solano. A la derecha, fuera de plano, el Puente de San Josâ”œآ® y el râ”œآ،o Huerva. Fuente visual: www.lacasadelbaloncesto.es/Visor.asp?id=1160&Fon=430', 1958, 1958, 1958, 'Anos 50', 'CENTRO', 41.64886500, -0.87608400, '0101000020E61000004B901150E108ECBF704221020ED34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/15481468252.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/15481468252.webp', 'https://www.flickr.com/photos/zaragozaantigua/15481468252/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.photos VALUES (25585, 'Soto del Puente de San Josâ”œآ® 1865', 'Plano del Soto del Puente de San Josâ”œآ®, Antonio Berbegal, Zaragoza, 1865. Terrenos de soto entre el râ”œآ،o Huerva y el paseo de la Mina, dedicados a viveros municipales, luego Club de Tenis y hoy Centro de Convivencia para Mayores Pedro Laâ”œآ،n Entralgo. El puente que aparece arriba a la izquierda es una construcciâ”œâ”‚n auxiliar: el puente de San Josâ”œآ® no figura en el plano. Fuente: AMZ.', 1865, 1865, 1865, 'Siglo XIX', 'CENTRO', 41.64871100, -0.87650300, '0101000020E61000008411FB04500CECBF19C748F608D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/20846116320.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/20846116320.webp', 'https://www.flickr.com/photos/zaragozaantigua/20846116320/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
