INSERT INTO public.photos VALUES (25796, 'Puerta del Duque de la Victoria 1861', '"Puerta del Duque de la Victoria, erigida en honor del general Baldomero Espartero, y costeada a sus expensas por Juan Bruil, que se abriâ”œâ”‚ al pâ”œâ•‘blico el 5 de octubre de 1861 y que permaneciâ”œâ”‚ en pie hasta 1919. Esta puerta en hierro, fundida en Inglaterra e instalada bajo la direcciâ”œâ”‚n del arquitecto Josâ”œآ® de Yarza Miâ”œâ–’ana, sustituâ”œآ،a a la primera puerta hecha de ladrillo, que fue erigida en 1856 y que se vino abajo, poco tiempo despuâ”œآ®s, por la precipitaciâ”œâ”‚n con la que fue construida." Josâ”œآ® Antonio Hernâ”œأ­ndez Latas. Fuente: Mariano Jâ”œâ•‘dez y Ortiz. â”œأ¼lbum de Andrâ”œآ®s Martâ”œآ،n e Ipâ”œأ­s. Colecciâ”œâ”‚n Mariano Martâ”œآ،n Casalderrey. Libro Primeros tiempos de la fotografâ”œآ،a en Zaragoza.', 1861, 1861, 1861, 'Siglo XIX', 'CENTRO', 41.64948600, -0.87610900, '0101000020E61000008466D7BD1509ECBFDD9A745B22D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14710337490.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14710337490.webp', 'https://www.flickr.com/photos/zaragozaantigua/14710337490/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
