INSERT INTO public.photos VALUES (25798, 'Plaza de San Miguel c.1895', 'Imagen de la plaza de San Miguel, con detalle de la iglesia, y su torre, antes de la intervenciâ”œâ”‚n de 1898, en la que se instalâ”œâ”‚ un nuevo chapitel modernista diseâ”œâ–’ado por Ricardo Magdalena, consistente en un campanil de hierro forjado con decoraciâ”œâ”‚n floral y lineal, rematado por una aguja câ”œâ”‚nica. Fuente visual: AHPZ-Archivo Coyne.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64977100, -0.87608900, '0101000020E6100000BD546CCCEB08ECBFD27135B22BD34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/14878507374.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/14878507374.webp', 'https://www.flickr.com/photos/zaragozaantigua/14878507374/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
