INSERT INTO public.photos VALUES (25800, 'Iglesia de San Miguel c.1895', '"Tower of la Seo. Zaragoza", ilustraciâ”œâ”‚n para "Glories of Spain", un tanto desnortada, pues es la torre de la iglesia de San Miguel de los Navarros, en su versiâ”œâ”‚n anterior a la moderna intervenciâ”œâ”‚n de Ricardo Magdalena, en 1898. Fuente visual: Charles W. Wood, New York, 1901.', 1895, 1895, 1895, 'Siglo XIX', 'CENTRO', 41.64958700, -0.87634200, '0101000020E6100000368FC360FE0AECBF1074B4AA25D34440', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/18898974593.webp', 'https://ktnavneugmimhdvpnnga.supabase.co/storage/v1/object/public/uploads/thumbs/18898974593.webp', 'https://www.flickr.com/photos/zaragozaantigua/18898974593/', 'Zaragoza Antigua (Flickr)', 'Uso educativo', NULL, '2026-02-21 14:16:04.847024', '2026-04-11 12:55:05.440923') ON CONFLICT (id) DO NOTHING;
